use std::collections::HashMap;
use std::sync::{Arc, Mutex};

struct CacheEntry {
    data: String,
    ttl_nanos: u64,
}
impl CacheEntry {
    fn is_expired(&self, current_time: u64) -> bool {
        (current_time.saturating_sub(self.ttl_nanos)) > 0
    }
}
struct DnsResolver {
    cache: Mutex<HashMap<String, CacheEntry>>,
}
impl DnsResolver {
    fn new() -> Self {
        DnsResolver { cache: Mutex::new(HashMap::new()) }
    }

    fn resolve_with_cache(&self, hostname: &str) -> Option<String> {
        let mut cache = self.cache.lock().unwrap();
        if let Some(entry) = cache.get(hostname) {
            let current_time = std::time::SystemTime::now().duration_since(std::time::UNIX_EPOCH).unwrap().as_nanos() as u64;
            if !entry.is_expired(current_time) {
                return Some(entry.data.clone());
            }
        }

        // Simulate external DNS lookup and cache update
        println!("Cache miss or expired. Performing actual network lookup for {}", hostname);
        let new_result = format!("resolved_ip_for_{}", hostname);

        let new_entry = CacheEntry {
            data: new_result.clone(),
            ttl_nanos: 30 * 1_000_000_000 // 30 seconds TTL
        };

        cache.insert(hostname.to_string(), new_entry);
        Some(new_result)
    }
}

fn main() {
    let resolver = Arc::new(DnsResolver::new());

    println!("--- First Lookup ---");
    if let Some(ip) = resolver.resolve_with_cache("example.com") {
        println!("Result: {}", ip);
    }

    std::thread::sleep(std::time::Duration::from_millis(50));

    println!("n--- Second Lookup (Should use cache) ---");
    if let Some(ip) = resolver.resolve_with_cache("example.com") {
        println!("Result: {}", ip);
    }
}

use std::collections::VecDeque;

struct KeyPacket {
    id: u32,
    data: Vec<u8>,
}

impl From<&KeyPacket> for String {
    fn from(packet: &KeyPacket) -> Self {
        format!("Processing packet ID: {}", packet.id)
    }
}

fn calculate_value(data: &[u8]) -> u64 {
    let mut sum: u64 = 0;
    for byte in data { 
        sum += *byte as u64;
    }
    sum
}

fn process_key_stream(input_packets: Vec<KeyPacket>) -> Vec<(u32, u64)> {
    let mut successful_results: Vec<(u32, u64)> = Vec::new();

    for packet in input_packets {
        let calculated_value = calculate_value(&packet.data);
        if calculated_value > 1000 {
            successful_results.push((packet.id, calculated_value));
        }
    }
    successful_results
}

fn main() {
    let packets = vec![ 
        KeyPacket { id: 101, data: vec![0xAA, 0xBB] }, 
        KeyPacket { id: 202, data: vec![0xFF, 0xEE, 0xDD] }, 
        KeyPacket { id: 303, data: vec![0x11, 0x22] } 
    ];

    let results = process_key_stream(packets);

    println!("Successfully processed records count: {}", results.len());
    for (id, value) in results {
        println!("Result for ID {}: {}", id, value);
    }
}

use std::collections::HashMap;

struct ConnectionState {
    last_seen: std::time::Instant,
    data_sent: u64,
}

fn process_packet(ip_src: &str, ip_dst: &str, payload_size: usize) -> Result<(), String> {
    let mut tracking_table: HashMap<String, ConnectionState> = HashMap::new();

    let key = format!("{}:{}", ip_src, ip_dst);
    if let Some(state) = tracking_table.get_mut(&key) {
        state.data_sent += payload_size as u64;
        println!("Tracking connection {}: Sent {} bytes total.", &key, state.data_sent);
    } else {
        tracking_table.insert(key.clone(), ConnectionState { 
            last_seen: std::time::Instant::now(),
            data_sent: payload_size as u64,
        });
        println!("New connection established and tracked: {}", &key);
    }
    Ok(())
}

fn main() {
    process_packet("192.168.1.10", "8.8.8.8", 140).unwrap();
    process_packet("192.168.1.10", "8.8.8.8", 50).unwrap();
    process_packet("10.0.0.5", "1.1.1.1", 300).unwrap();
}

use std::collections::HashMap;

struct ImageLayer {
    name: String,
    contents: HashMap<String, u64>,
}

impl ImageLayer {
    fn calculate_derived_size(&self) -> u64 {
        self.contents.values().sum()
    }
}

fn process_layers(layers: Vec<ImageLayer>) -> Vec<u64> {
    let mut results = Vec::new();
    for layer in layers {
        let size = layer.calculate_derived_size();
        results.push(size);
    }
    results
}

fn main() {
    use std::collections::HashMap;

    let mut map1 = HashMap::new();
    map1.insert("fileA".to_string(), 100);
    map1.insert("fileB".to_string(), 256);

    let layer1 = ImageLayer {
        name: "base".to_string(),
        contents: map1
    };

    let mut map2 = HashMap::new();
    map2.insert("fileC".to_string(), 50);

    let layer2 = ImageLayer {
        name: "overlay".to_string(),
        contents: map2
    };

    let layers_array = vec![layer1, layer2];

    let final_sizes = process_layers(layers_array);

    for (index, &size) in final_sizes.iter().enumerate() {
        println!("Processed element {}: Total Size {}", index, size);
    }
}
